    logger.warn(targetPath, `replacing existing directory`);
    // OR: logger.detail(`! replacing existing directory: ${targetPath}`)
  }
```

The `warn()` method or a plain `detail()` call — both work. Using `logger.warn(targetPath, "replacing existing directory")` is the more consistent choice since it goes through the yellow `!` symbol path.

---

### 3. How `revert.ts` uses the logger

**Import addition:**
```typescript
import { logger } from "../logger.ts";
```

**Not-found skip:**

Before:
```typescript
console.log(`  \x1b[33m-\x1b[0m ${label} (not found, skipping)`);
```
After:
```typescript
logger.skip(label, "(not found, skipping)");
```

**Dry-run:**

Before:
```typescript
console.log(`  \x1b[36m○\x1b[0m ${label}`);
if (verbose) {
  console.log(`    would remove: ${action.target}`);
}
```
After:
```typescript
logger.plan(label);
if (verbose) {
  logger.detail(`would remove: ${action.target}`);
}
```

**Success:**

Before:
```typescript
console.log(`  \x1b[32m✓\x1b[0m ${label}`);
if (verbose) {
  console.log(`    removed: ${action.target}`);
}
```
After:
```typescript
logger.ok(label);
if (verbose) {
  logger.detail(`removed: ${action.target}`);
}
```

**Failure:**

Before:
```typescript
console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
```
After:
```typescript
logger.fail(label, msg);
```

---

### 4. How `index.ts` uses the logger

**Import addition:**
```typescript
import { logger } from "./logger.ts";
```

**Help output** — this is intentionally not routed through `logger` because it should always print and is not a status message. Keep `console.log(USAGE)` as-is, or route through `logger.info(USAGE)`. Given that help must always print (even when tests silence output), `console.log` is the right choice here.

**Verbose agent detection messages:**

Before:
```typescript
console.log(`Using specified agents: ${detectedAgents.join(", ")}`);
// ...
console.log(`Detected agents: ${detectedAgents.join(", ")}`);
```
After:
```typescript
logger.info(`Using specified agents: ${detectedAgents.join(", ")}`);
// ...
logger.info(`Detected agents: ${detectedAgents.join(", ")}`);
```

**No agents detected:**

Before:
```typescript
console.log("No supported AI agents detected on this system.");
console.log(`Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`);
```
After:
```typescript
logger.info("No supported AI agents detected on this system.");
logger.info(`Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`);
```

**No skills to deploy/revert:**

Before:
```typescript
console.log("No skills to deploy for detected agents.");
```
After:
```typescript
logger.info("No skills to deploy for detected agents.");
```

**Dry-run prefix and deploy/revert header lines:**

Before:
```typescript
const prefix = options.dryRun ? "\x1b[36m[dry-run]\x1b[0m " : "";
console.log(`${prefix}Deploying ${actions.length} skill(s):`);
```
After: The `logger` owns the ANSI, so `index.ts` should not reconstruct the cyan prefix. Two options:

Option A — Add a dedicated `header(dryRun, msg)` method on Logger. This is over-engineering for a single call site.

Option B — Keep `info()` and let the caller construct the dry-run text without ANSI:
```typescript
const prefix = options.dryRun ? "[dry-run] " : "";
logger.info(`${prefix}Deploying ${actions.length} skill(s):`);
```
This loses the cyan color on the dry-run prefix. Given the requirement says "same 4 colors: cyan for `[dry-run]` prefix", a better option is:

Option C — Add an `infoWithDryRun(dryRun: boolean, msg: string)` method. Still over-engineering.

Option D — The cleanest minimal approach: add a single `dryRunPrefix(dryRun: boolean): string` helper exported from `logger.ts`:
```typescript
export function dryRunPrefix(dryRun: boolean): string {
  const isTTY = Boolean(process.stdout.isTTY);
  return dryRun ? (isTTY ? `\x1b[36m[dry-run]\x1b[0m ` : `[dry-run] `) : "";
}
```
Then in `index.ts`:
```typescript
import { logger, dryRunPrefix } from "./logger.ts";
// ...
logger.info(`${dryRunPrefix(options.dryRun)}Deploying ${actions.length} skill(s):`);
```

This is clean, testable, and does not bloat the Logger interface.

**Summary line after deploy:**

Before:
```typescript
console.log();
console.log(`${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`);
```
After:
```typescript
logger.info("");
logger.info(`${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`);
```

**Error handlers at the bottom of `index.ts`:**

Before:
```typescript
console.error(`Error: ${err.message}`);
if (debugMode) { console.error(err); }
// ...
console.error("Unexpected error. Run with --debug for details.");
if (debugMode) { console.error(err); }
```
After:
```typescript
logger.error(`Error: ${err.message}`);
if (debugMode) { logger.errorRaw(err); }
// ...
logger.error("Unexpected error. Run with --debug for details.");
if (debugMode) { logger.errorRaw(err); }
```

Note: the error handlers live outside `main()` in the top-level `try/catch`. The `logger` singleton is imported at module level, so it is available there.

---

### 5. How tests silence the logger

The tests in `test/deploy.test.ts` and `test/revert.test.ts` import `executeDeploy`/`executeRevert` directly. Because `logger` is a module-level singleton exported from `src/logger.ts`, tests import it and call `silence()` once at the top of the file:

```typescript
// At the top of test/deploy.test.ts and test/revert.test.ts
import { logger } from "../src/logger.ts";
logger.silence();
```

This works because:
- Node.js ESM module caching ensures `../src/logger.ts` resolves to the same module instance that `deploy.ts` and `revert.ts` import via `../logger.ts`.
- `silence()` flips the shared `silent` flag before any test runs.
- No changes to test call signatures. `executeDeploy(actions, false, false)` still works exactly as before.
- No `before()`/`beforeEach()` hooks required — `logger.silence()` at module scope runs once on load.

A test that needs to verify output behavior (not currently present, but possible in future) can use `createLogger()` instead:

```typescript
// Future test pattern if output verification is needed
import { createLogger } from "../src/logger.ts";
const testLogger = createLogger();
// Then somehow inject it... but this requires a different approach since logger is a singleton.
```

For the current state of the project (tests only verify filesystem effects, not output), `logger.silence()` at import time is sufficient and requires zero architectural complexity.

---

### 6. File structure and imports

**New file:**
```
src/logger.ts
```

**Modified files:**
```
src/index.ts       — add: import { logger, dryRunPrefix } from "./logger.ts";
src/core/deploy.ts — add: import { logger } from "../logger.ts";
src/core/revert.ts — add: import { logger } from "../logger.ts";
test/deploy.test.ts — add: import { logger } from "../src/logger.ts"; logger.silence();
test/revert.test.ts — add: import { logger } from "../src/logger.ts"; logger.silence();
```

No new directories, no `tsconfig.json` changes, no `package.json` changes.

---

### 7. Implementation sequence

1. Create `src/logger.ts` with the full `Logger` interface, `createLogger()` factory, `logger` singleton, and `dryRunPrefix()` helper.
2. Update `src/core/deploy.ts` — add import, replace all `console.log`/`console.error` + ANSI strings in `executeDeploy` and `removeExisting`.
3. Update `src/core/revert.ts` — add import, replace all `console.log`/`console.error` + ANSI strings in `executeRevert`.
4. Update `src/index.ts` — add import, replace all `console.log`/`console.error` except `console.log(USAGE)` (which can stay or become `logger.info(USAGE)`), replace the ANSI dry-run prefix with `dryRunPrefix()`.
5. Update `test/deploy.test.ts` — add two lines at the top.
6. Update `test/revert.test.ts` — add two lines at the top.
7. Run `npm run typecheck` to confirm no type errors.
8. Run `npm test` to confirm all tests pass with no ANSI output.

---

### Potential pitfalls

- **`removeExisting` verbose output**: It uses `console.log` with an indented `!` symbol. The method signature `removeExisting(targetPath, verbose)` does not change. Since it accesses the module-level `logger` singleton directly, no signature change is needed.
- **`errorRaw` and `erasableSyntaxOnly`**: The `tsconfig` has `erasableSyntaxOnly: true` which means no enums or namespaces. The `Logger` interface and `createLogger` function are plain class-free TypeScript — compatible.
- **The `console.log(USAGE)` at the start of `main()`**: This one can legitimately stay as `console.log` since it only fires when `--help` is passed and tests never invoke the `main()` function. However, routing it through `logger.info(USAGE)` is also fine since tests call `logger.silence()` at import time.
- **TTY detection timing**: `process.stdout.isTTY` is evaluated at `createLogger()` call time (module load). This is correct — it will not change during a process lifetime, and is the standard pattern.

---

### Critical Files for Implementation

- `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/core/deploy.ts` - All ANSI + console calls to replace; `removeExisting` helper needs attention
- `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/core/revert.ts` - All ANSI + console calls to replace
- `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/index.ts` - Top-level error handlers + dry-run prefix logic to migrate
- `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/errors.ts` - Pattern to follow for the Logger interface style (typed, minimal, no classes)
- `/Users/damianpiatkowski/Documents/workspace/inception-engine/test/deploy.test.ts` - Entry point for silencing; pattern to follow for revert test file

