    77→    } else if (!directory) {
    78→      directory = arg;
    79→    } else {
    80→      throw new UserError("INVALID_ARGS", `Unexpected argument: ${arg}`);
    81→    }
    82→    i++;
    83→  }
    84→
    85→  if (!directory) {
    86→    throw new UserError("INVALID_ARGS", "Missing required <directory> argument");
    87→  }
    88→
    89→  return { command, directory: path.resolve(directory), dryRun, agents, verbose, debug };
    90→}
