     1→#!/usr/bin/env node
     2→
     3→import path from "node:path";
     4→import { AGENT_IDS } from "./types.ts";
     5→import type { AgentId, CliOptions } from "./types.ts";
     6→import { loadManifest } from "./config/manifest.ts";
     7→import { AGENT_REGISTRY } from "./config/agents.ts";
     8→import { resolveHome } from "./core/resolve.ts";
     9→import { detectInstalledAgents } from "./core/detect.ts";
    10→import { planDeploy, executeDeploy } from "./core/deploy.ts";
    11→import { planRevert, executeRevert } from "./core/revert.ts";
    12→import { UserError } from "./errors.ts";
    13→import type { ErrorCode } from "./errors.ts";
    14→
    15→const USAGE = `
    16→inception-engine - Deploy AI agent skills
    17→
    18→Usage:
    19→  inception-engine <directory> [options]
    20→  inception-engine revert <directory> [options]
    21→
    22→Options:
    23→  --dry-run        Show what would be done without doing it
    24→  --agents <list>  Comma-separated list of agent IDs to target
    25→  --verbose        Show detailed output
    26→  --debug          Show full error stack traces
    27→  --help           Show this help message
    28→
    29→Supported agents:
    30→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
    31→`.trim();
    32→
    33→function parseArgs(argv: string[]): CliOptions {
    34→  const args = argv.slice(2);
    35→
    36→  if (args.length === 0 || args.includes("--help")) {
    37→    return { command: "help", directory: "", dryRun: false, agents: null, verbose: false, debug: false };
    38→  }
    39→
    40→  let command: "deploy" | "revert" = "deploy";
    41→  let directory = "";
    42→  let dryRun = false;
    43→  let agents: AgentId[] | null = null;
    44→  let verbose = false;
    45→  let debug = false;
    46→
    47→  let i = 0;
    48→  if (args[0] === "revert") {
    49→    command = "revert";
    50→    i = 1;
    51→  }
    52→
    53→  while (i < args.length) {
    54→    const arg = args[i]!;
    55→
    56→    if (arg === "--dry-run") {
    57→      dryRun = true;
    58→    } else if (arg === "--verbose") {
    59→      verbose = true;
    60→    } else if (arg === "--debug") {
    61→      debug = true;
    62→    } else if (arg === "--agents") {
    63→      i++;
    64→      const next = args[i];
    65→      if (!next) {
    66→        throw new UserError("INVALID_ARGS", "--agents requires a comma-separated list");
    67→      }
    68→      const ids = next.split(",").map((s) => s.trim());
    69→      for (const id of ids) {
    70→        if (!AGENT_IDS.includes(id as AgentId)) {
    71→          throw new UserError("INVALID_ARGS", `Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`);
    72→        }
    73→      }
    74→      agents = ids as AgentId[];
    75→    } else if (arg.startsWith("--")) {
    76→      throw new UserError("INVALID_ARGS", `Unknown option: ${arg}`);
    77→    } else if (!directory) {
    78→      directory = arg;
    79→    } else {
    80→      throw new UserError("INVALID_ARGS", `Unexpected argument: ${arg}`);
    81→    }
    82→    i++;
    83→  }
    84→
    85→  if (!directory) {
    86→    throw new UserError("INVALID_ARGS", "Missing required <directory> argument");
    87→  }
    88→
    89→  return { command, directory: path.resolve(directory), dryRun, agents, verbose, debug };
    90→}
    91→
    92→async function main(): Promise<number> {
    93→  const options = parseArgs(process.argv);
    94→
    95→  if (options.command === "help") {
    96→    console.log(USAGE);
    97→    return 0;
    98→  }
    99→
   100→  const manifest = await loadManifest(options.directory);
   101→  const home = resolveHome();
   102→
   103→  let detectedAgents: AgentId[];
   104→  if (options.agents) {
   105→    detectedAgents = options.agents;
   106→    if (options.verbose) {
   107→      console.log(`Using specified agents: ${detectedAgents.join(", ")}`);
   108→    }
   109→  } else {
   110→    detectedAgents = await detectInstalledAgents(home);
   111→    if (detectedAgents.length === 0) {
   112→      console.log("No supported AI agents detected on this system.");
   113→      console.log(`Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`);
   114→      return 0;
   115→    }
   116→    if (options.verbose) {
   117→      console.log(`Detected agents: ${detectedAgents.join(", ")}`);
   118→    }
   119→  }
   120→
   121→  const prefix = options.dryRun ? "\x1b[36m[dry-run]\x1b[0m " : "";
   122→
   123→  if (options.command === "deploy") {
   124→    const actions = planDeploy(manifest, options.directory, detectedAgents, home);
   125→    if (actions.length === 0) {
   126→      console.log("No skills to deploy for detected agents.");
   127→      return 0;
   128→    }
   129→
   130→    console.log(`${prefix}Deploying ${actions.length} skill(s):`);
   131→    const { succeeded, failed } = await executeDeploy(actions, options.dryRun, options.verbose);
   132→
   133→    console.log();
   134→    if (failed.length > 0) {
   135→      console.log(`${succeeded} succeeded, ${failed.length} failed`);
   136→      return 1;
   137→    } else {
   138→      console.log(`${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`);
   139→    }
   140→  } else {
   141→    const actions = planRevert(manifest, detectedAgents, home);
   142→    if (actions.length === 0) {
   143→      console.log("No skills to revert for detected agents.");
   144→      return 0;
   145→    }
   146→
   147→    console.log(`${prefix}Reverting ${actions.length} skill(s):`);
   148→    const { succeeded, skipped } = await executeRevert(actions, options.dryRun, options.verbose);
   149→
   150→    console.log();
   151→    const parts = [`${succeeded} removed`];
   152→    if (skipped > 0) parts.push(`${skipped} skipped`);
   153→    console.log(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
   154→  }
   155→
   156→  return 0;
   157→}
   158→
   159→const USER_ERROR_EXIT: Record<ErrorCode, number> = {
   160→  INVALID_ARGS: 2,
   161→  MANIFEST_INVALID: 3,
   162→  DEPLOY_FAILED: 1,
   163→  RESOLVE_FAILED: 1,
   164→};
   165→
   166→const debugMode = process.argv.includes("--debug");
   167→
   168→try {
   169→  process.exit(await main());
   170→} catch (err) {
   171→  if (err instanceof UserError) {
   172→    console.error(`Error: ${err.message}`);
   173→    if (debugMode) {
   174→      console.error(err);
   175→    }
   176→    process.exit(USER_ERROR_EXIT[err.code]);
   177→  } else {
   178→    console.error("Unexpected error. Run with --debug for details.");
   179→    if (debugMode) {
   180→      console.error(err);
   181→    }
   182→    process.exit(1);
   183→  }
   184→}
