     1→import { access, lstat, mkdir, symlink, cp, unlink, rm } from "node:fs/promises";
     2→import type { Stats } from "node:fs";
     3→import path from "node:path";
     4→import { AGENT_REGISTRY } from "../config/agents.ts";
     5→import { resolveAgentSkillPath, getDeployMethod } from "./resolve.ts";
     6→import { UserError } from "../errors.ts";
     7→import type { AgentId, DeployAction, Manifest } from "../types.ts";
     8→
     9→export function planDeploy(
    10→  manifest: Manifest,
    11→  sourceDir: string,
    12→  detectedAgents: AgentId[],
    13→  home: string
    14→): DeployAction[] {
    15→  const method = getDeployMethod();
    16→  const actions: DeployAction[] = [];
    17→  const resolvedSourceDir = path.resolve(sourceDir);
    18→
    19→  for (const skill of manifest.skills) {
    20→    const source = path.resolve(sourceDir, skill.path);
    21→
    22→    if (source !== resolvedSourceDir && !source.startsWith(resolvedSourceDir + path.sep)) {
    23→      throw new UserError(
    24→        "DEPLOY_FAILED",
    25→        `Skill path "${skill.path}" resolves outside the repository root: ${source}`
    26→      );
    27→    }
    28→
    29→    for (const agentId of skill.agents) {
    30→      if (!detectedAgents.includes(agentId)) continue;
    31→
    32→      const agent = AGENT_REGISTRY.find((a) => a.id === agentId);
    33→      if (!agent) continue;
    34→
    35→      const target = resolveAgentSkillPath(agent, skill.name, home);
    36→
    37→      actions.push({ skill: skill.name, agent: agentId, source, target, method });
    38→    }
    39→  }
    40→
    41→  return actions;
    42→}
    43→
    44→export async function executeDeploy(
    45→  actions: DeployAction[],
    46→  dryRun: boolean,
    47→  verbose: boolean
    48→): Promise<{ succeeded: number; failed: Array<{ action: DeployAction; error: string }> }> {
    49→  let succeeded = 0;
    50→  const failed: Array<{ action: DeployAction; error: string }> = [];
    51→
    52→  for (const action of actions) {
    53→    const label = `${action.skill} -> ${action.agent}`;
    54→
    55→    try {
    56→      await access(action.source);
    57→    } catch {
    58→      const msg = `Source not found: ${action.source}`;
    59→      failed.push({ action, error: msg });
    60→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    61→      continue;
    62→    }
    63→
    64→    if (dryRun) {
    65→      console.log(`  \x1b[36m○\x1b[0m ${label}`);
    66→      if (verbose) {
    67→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    68→      }
    69→      succeeded++;
    70→      continue;
    71→    }
    72→
    73→    try {
    74→      await removeExisting(action.target, verbose);
    75→      await mkdir(path.dirname(action.target), { recursive: true });
    76→
    77→      if (action.method === "symlink") {
    78→        await symlink(action.source, action.target, "dir");
    79→      } else {
    80→        await cp(action.source, action.target, { recursive: true });
    81→      }
    82→
    83→      console.log(`  \x1b[32m✓\x1b[0m ${label}`);
    84→      if (verbose) {
    85→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    86→      }
    87→      succeeded++;
    88→    } catch (err) {
    89→      const msg = err instanceof Error ? err.message : String(err);
    90→      failed.push({ action, error: msg });
    91→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    92→    }
    93→  }
    94→
    95→  return { succeeded, failed };
    96→}
    97→
    98→async function removeExisting(targetPath: string, verbose: boolean): Promise<void> {
    99→  let stat: Stats;
   100→  try {
   101→    stat = await lstat(targetPath);
   102→  } catch {
   103→    return;
   104→  }
   105→
   106→  if (stat.isSymbolicLink()) {
   107→    if (verbose) {
   108→      console.log(`    removing existing symlink: ${targetPath}`);
   109→    }
   110→    await unlink(targetPath);
   111→  } else {
   112→    if (verbose) {
   113→      console.log(`    \x1b[33m!\x1b[0m replacing existing directory: ${targetPath}`);
   114→    }
   115→    await rm(targetPath, { recursive: true });
   116→  }
   117→}
